#!/bin/bash
# OS4U v1.01.001 — Script COMPLETO de deploy
# Aplica TODOS os 20 arquivos modificados de uma vez
# Execute na raiz do repositório: bash apply_all_complete.sh

set -e
echo "🚀 OS4U v1.01.001 — Aplicando 20 arquivos..."
echo ""

# Verificar que estamos no repositório correto
if [ ! -f "render.yaml" ]; then
  echo "❌ Execute na raiz do repositório (onde está o render.yaml)"
  exit 1
fi

mkdir -p "frontend"
echo "📄 frontend/index.html"
echo "" | base64 -d > "frontend/index.html"

mkdir -p "frontend/public"
echo "📄 frontend/public/manifest.json"
echo "" | base64 -d > "frontend/public/manifest.json"

mkdir -p "frontend/public"
echo "📄 frontend/public/sw.js"
echo "" | base64 -d > "frontend/public/sw.js"

mkdir -p "frontend/public"
echo "📄 frontend/public/_worker.js"
echo "" | base64 -d > "frontend/public/_worker.js"

mkdir -p "frontend/public"
echo "📄 frontend/public/icon.svg"
echo "" | base64 -d > "frontend/public/icon.svg"

mkdir -p "frontend/src/layout"
echo "📄 frontend/src/layout/AppLayout.tsx"
echo "" | base64 -d > "frontend/src/layout/AppLayout.tsx"

mkdir -p "frontend/src/layout"
echo "📄 frontend/src/layout/Sidebar.tsx"
echo "" | base64 -d > "frontend/src/layout/Sidebar.tsx"

mkdir -p "frontend/src/layout"
echo "📄 frontend/src/layout/BottomNav.tsx"
echo "" | base64 -d > "frontend/src/layout/BottomNav.tsx"

mkdir -p "frontend/src"
echo "📄 frontend/src/index.css"
echo "" | base64 -d > "frontend/src/index.css"

mkdir -p "frontend/src/pages"
echo "📄 frontend/src/pages/Inventory.tsx"
echo "" | base64 -d > "frontend/src/pages/Inventory.tsx"

mkdir -p "frontend/src/pages"
echo "📄 frontend/src/pages/Settings.tsx"
echo "" | base64 -d > "frontend/src/pages/Settings.tsx"

mkdir -p "frontend/src/pages"
echo "📄 frontend/src/pages/Suppliers.tsx"
echo "" | base64 -d > "frontend/src/pages/Suppliers.tsx"

mkdir -p "frontend/src/pages"
echo "📄 frontend/src/pages/Clients.tsx"
echo "" | base64 -d > "frontend/src/pages/Clients.tsx"

mkdir -p "frontend/src/components/orders"
echo "📄 frontend/src/components/orders/OrderDetails.tsx"
echo "" | base64 -d > "frontend/src/components/orders/OrderDetails.tsx"

mkdir -p "frontend/src/components"
echo "📄 frontend/src/components/QuickAdd.tsx"
echo "" | base64 -d > "frontend/src/components/QuickAdd.tsx"

mkdir -p "backend/src"
echo "📄 backend/src/main.ts"
echo "" | base64 -d > "backend/src/main.ts"

mkdir -p "backend/src/modules/users"
echo "📄 backend/src/modules/users/users.controller.ts"
echo "" | base64 -d > "backend/src/modules/users/users.controller.ts"

mkdir -p "backend/src/modules/users"
echo "📄 backend/src/modules/users/users.service.ts"
echo "" | base64 -d > "backend/src/modules/users/users.service.ts"

mkdir -p "backend/src/modules/settings"
echo "📄 backend/src/modules/settings/settings.module.ts"
echo "" | base64 -d > "backend/src/modules/settings/settings.module.ts"

echo ""
echo "✅ 20 arquivos aplicados com sucesso!"
echo ""

# Remover dados sensíveis do repo
git rm --cached backend/database.sqlite 2>/dev/null || true
git rm --cached backend/lib_interno_correct.sqlite 2>/dev/null || true
git rm --cached "frontend/src/pages/Orders.bak" 2>/dev/null || true
git rm -rf --cached tmp_v*/ 2>/dev/null || true

# Atualizar .gitignore
grep -q "*.sqlite" .gitignore 2>/dev/null || echo "*.sqlite" >> .gitignore
grep -q "*.bak" .gitignore 2>/dev/null || echo "*.bak" >> .gitignore
grep -q "tmp_v*" .gitignore 2>/dev/null || echo "tmp_v*/" >> .gitignore

echo "📦 Fazendo commit e push..."
git add .
git commit -m "feat: v1.01.001 — PWA, menu agrupado, Fornecedores, QuickAdd mobile, inventory, reset senha, WhatsApp fix, Android routing, segurança" --no-verify
git push origin main --no-verify

echo ""
echo "🎉 Deploy iniciado! Cloudflare e Render vão atualizar em ~3 minutos"
echo "🌐 Site: https://os4u.com.br"